// Cart System
let cart = [];
try {
  cart = JSON.parse(localStorage.getItem('velora_cart')) || [];
} catch (e) {
  console.warn('localStorage is not available:', e);
}

function addToCart(productId, event) {
  if (event) event.preventDefault();
  
  const product = products.find(p => p.id === productId);
  if (!product) return;

  const existingItem = cart.find(item => item.id === productId);
  
  if (existingItem) {
    existingItem.quantity += 1;
  } else {
    cart.push({
      id: product.id,
      name: product.name,
      price: product.salePrice || product.price,
      image: product.image,
      quantity: 1,
      size: product.sizes[0],
      color: product.colors[0]
    });
  }

  saveCart();
  updateCartCount();
  renderCartDrawer();
  
  if (event && event.target) {
    event.target.classList.add('pulse-anim');
    setTimeout(() => event.target.classList.remove('pulse-anim'), 300);
  }
  
  showToast(`${product.name} added to cart`);
  
  // Open drawer
  const cartDrawer = document.getElementById('cart-drawer');
  const cartOverlay = document.getElementById('cart-overlay');
  if (cartDrawer && cartOverlay) {
    cartDrawer.classList.add('active');
    cartOverlay.classList.add('active');
  }
}

function removeFromCart(productId) {
  cart = cart.filter(item => item.id !== productId);
  saveCart();
  updateCartCount();
  renderCartDrawer();
  if (document.getElementById('cart-page-items')) {
    renderCartPage();
  }
}

function updateQty(productId, change) {
  const item = cart.find(i => i.id === productId);
  if (item) {
    item.quantity += change;
    if (item.quantity <= 0) {
      removeFromCart(productId);
    } else {
      saveCart();
      updateCartCount();
      renderCartDrawer();
      if (document.getElementById('cart-page-items')) {
        renderCartPage();
      }
    }
  }
}

function saveCart() {
  try {
    localStorage.setItem('velora_cart', JSON.stringify(cart));
  } catch (e) {
    console.warn('localStorage is not available:', e);
  }
}

function getCartTotal() {
  return cart.reduce((total, item) => total + (item.price * item.quantity), 0);
}

function getCartCount() {
  return cart.reduce((count, item) => count + item.quantity, 0);
}

function updateCartCount() {
  const countElements = document.querySelectorAll('.cart-badge');
  countElements.forEach(el => {
    el.textContent = getCartCount();
  });
}

function renderCartDrawer() {
  const container = document.getElementById('cart-drawer-items');
  const totalEl = document.getElementById('cart-drawer-total');
  
  if (!container || !totalEl) return;

  if (cart.length === 0) {
    container.innerHTML = '<div class="text-center text-muted mt-4">Your cart is empty</div>';
    totalEl.textContent = `${CURRENCY} 0`;
    return;
  }

  container.innerHTML = cart.map(item => `
    <div class="cart-item">
      <img src="${item.image}" alt="${item.name}" class="cart-item-img">
      <div class="cart-item-details">
        <div class="cart-item-title">${item.name}</div>
        <div class="cart-item-meta">Size: ${item.size} | Color: <span style="display:inline-block;width:10px;height:10px;background:${item.color};border-radius:50%;"></span></div>
        <div class="cart-item-price">${CURRENCY} ${item.price}</div>
        <div class="qty-controls">
          <button class="qty-btn" onclick="updateQty(${item.id}, -1)">-</button>
          <span>${item.quantity}</span>
          <button class="qty-btn" onclick="updateQty(${item.id}, 1)">+</button>
        </div>
        <button class="btn cart-item-remove" onclick="removeFromCart(${item.id})">Remove</button>
      </div>
    </div>
  `).join('');

  totalEl.textContent = `${CURRENCY} ${getCartTotal()}`;
}

// Initialize
document.addEventListener('DOMContentLoaded', () => {
  updateCartCount();
  renderCartDrawer();
});

